void update_system_config_name(const char *name) {
    k_mutex_lock(&config_mutex, K_FOREVER);
    strncpy(system_config.name, name, sizeof(system_config.name) - 1);
    system_config.name[sizeof(system_config.name) - 1] = '\0'; // Ensure null-termination
    printk("ADMIN: Updated config_name to '%s'\n", system_config.name);
    k_mutex_unlock(&config_mutex);
}

