                    break;
                case OP_CONFIG_UPDATE_B:
                    update_system_config_b(request.params.config_update_b.value);
                    break;
                case OP_CONFIG_UPDATE_NAME:
                    update_system_config_name(request.params.config_update_name.name);
                    break;
                case OP_NONE:
